HRESULT MRFTWI::SetTWINSDs(const CATListValCATBaseUnknown_var &spOnTWINSDsList)
{
	int sizeOfAngRefList = spOnTWINSDsList.Size();
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForTWI, this);

	if ((sizeOfAngRefList > 0) && (!!FeatFacadeOnGrooveSweep))
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValueOnCurve;
		AttrKey = CATFmAttributeName(_MRFTWINSDList);
		FeatFacadeOnGrooveSweep.UnsetValue(AttrKey);

		for (int i = 1; i <= sizeOfAngRefList; i++)
		{
			CATBaseUnknown_var angleRef = spOnTWINSDsList[i];

			CATFmAttributeValue FmAttrValue;
			FmAttrValue.SetFeature(angleRef);

			FmAttrValueOnCurve.Append(FmAttrValue);
		}
		if (FmAttrValueOnCurve.Size() > 0)
		{
			rc = FeatFacadeOnGrooveSweep.SetValue(AttrKey, FmAttrValueOnCurve);
			if (SUCCEEDED(rc))
			{
				//UpdateFeature();
			}
		}
	}
	return rc;
}


HRESULT MRFTWI::GetTWINSDs(CATListValCATBaseUnknown_var &spOnTWINSDsList)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForTWI, this);

	CATFmAttributeName AttrKey;
	CATFmAttributeValue FmAttrValueList;
	AttrKey = CATFmAttributeName(_MRFTWINSDList);

	if (!!FeatFacadeOnGrooveSweep)
	{
		rc = FeatFacadeOnGrooveSweep.GetValue(AttrKey, FmAttrValueList);

		if (SUCCEEDED(rc))
		{
			int listOfAngRefSize = FmAttrValueList.Size();

			for (int i = 1; i <= listOfAngRefSize; ++i)
			{
				CATFmAttributeValue FmAttrValue;
				rc = FeatFacadeOnGrooveSweep.GetValueAtIndex(AttrKey, i, FmAttrValue);

				if (SUCCEEDED(rc))
				{
					CATBaseUnknown_var nsd = FmAttrValue.GetFeature();
					if (!!nsd)
					{
						spOnTWINSDsList.Append(nsd);
					}
				}
			}
		}
	}
	return rc;

}




//-----------------------------------------------------------------------------
// MRFTWI : UpdateFeature
//Function: update the created feature.
//-----------------------------------------------------------------------------
void MRFTWI::UpdateFeature()
{
	CATFmFeatureFacade FeatFacadeOnTWI(_CredentialForTWI, this);
	HRESULT rc = FeatFacadeOnTWI.IsUpToDate();
	if (S_FALSE == rc)
	{
		rc = FeatFacadeOnTWI.Update();
		if (SUCCEEDED(rc))
		{
			CATBaseUnknown *pTWIObject = NULL;
			rc = FeatFacadeOnTWI.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)&pTWIObject);
			if (SUCCEEDED(rc) && NULL != pTWIObject)
			{
				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(pTWIObject, 0, 0);
				
				pTWIObject->Release();
				pTWIObject = NULL;
			}
		}
	}
}

